import { zonedTimeToUtc } from 'date-fns-tz';
import { convertTzToUtc, convertUtcToTz, formatToISO } from '../../newUtils';

/**
 * Предикаты для явной и читабельной ветвизации логики.
 */
export const isValidDate = (d?: Date | null): d is Date => !!d && !Number.isNaN(d.getTime());
export const hasStartedRange = (start?: Date | null): boolean => isValidDate(start);
export const hasFilledRange = (end?: Date | null): boolean => isValidDate(end);

/**
 * Строит локальную дату из координат клика в календаре и опциональных часов/минут.
 */
export const buildLocalFromClick = (
	day: number,
	month: number,
	year: number,
	hours?: number,
	minutes?: number,
): Date => {
	const h = typeof hours === 'number' ? hours : 0;
	const m = typeof minutes === 'number' ? minutes : 0;
	return new Date(year, month, day, h, m, 0, 0);
};

/**
 * Конвертирует локальную дату в представление UTC с учётом режима таймпикера.
 */
export const toUTCFromLocal = (localDate: Date, enableTimePicker: boolean, effectiveTimeZone: string): Date => {
	if (!enableTimePicker) {
		return localDate;
	}

	if (effectiveTimeZone) {
		const year = localDate.getFullYear();
		const month = localDate.getMonth() + 1;
		const day = localDate.getDate();
		const hours = localDate.getHours();
		const minutes = localDate.getMinutes();
		const seconds = localDate.getSeconds();

		const dateString = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')} ${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;

		return zonedTimeToUtc(dateString, effectiveTimeZone);
	}

	// Сохраняем текущую логику: собираем UTC напрямую из локальных компонентов даты/времени.
	return new Date(
		Date.UTC(
			localDate.getFullYear(),
			localDate.getMonth(),
			localDate.getDate(),
			localDate.getHours(),
			localDate.getMinutes(),
			0,
			0,
		),
	);
};

/**
 * Форматирует дату UTC в выходную строку по заданному формату.
 */
export const toOutputString = (dateUTC: Date, outputDateFormat: string): string => {
	return formatToISO(dateUTC, outputDateFormat);
};

/**
 * Сравнивает только календарный день (год, месяц, число) между двумя датами UTC.
 */
export const isSameCalendarDayUTC = (aUTC: Date, bUTC: Date): boolean => {
	return (
		aUTC.getUTCFullYear() === bUTC.getUTCFullYear() &&
		aUTC.getUTCMonth() === bUTC.getUTCMonth() &&
		aUTC.getUTCDate() === bUTC.getUTCDate()
	);
};

/**
 * Вычисляет следующий диапазон при клике по дню.
 * Возвращает кортеж строк [start, end]. Пустой конец представлен как ''.
 */
export const computeNextRangeOnDayClick = (args: {
	startUTC?: Date | null;
	endUTC?: Date | null;
	localDate: Date;
	newUTC: Date;
	enableTimePicker: boolean;
	disabledStartDate: boolean;
	disabledEndDate: boolean;
	outputDateFormat: string;
	originalStartStr?: string; // сохраняем исходное время старта при выборе конца в режиме времени
	pickerStartTime?: { hours: string; minutes: string };
	effectiveTimeZone?: string;
}): [string, string] => {
	const {
		startUTC,
		endUTC,
		localDate,
		newUTC,
		enableTimePicker,
		disabledStartDate,
		disabledEndDate,
		outputDateFormat,
		originalStartStr,
		pickerStartTime,
		effectiveTimeZone,
	} = args;

	const started = hasStartedRange(startUTC);
	const filled = hasFilledRange(endUTC);

	const startStr = started && startUTC ? toOutputString(startUTC, outputDateFormat) : '';
	const endStr = filled && endUTC ? toOutputString(endUTC, outputDateFormat) : '';

	const newStr = enableTimePicker ? newUTC.toISOString() : toOutputString(newUTC, outputDateFormat);

	// Заблокирован только старт: разрешаем менять только конец
	if (disabledStartDate && !disabledEndDate) {
		if (started && startUTC && localDate.getTime() <= startUTC.getTime()) {
			return [startStr, startStr];
		}
		return [startStr, newStr];
	}

	// Заблокирован только конец: разрешаем менять только старт
	if (!disabledStartDate && disabledEndDate) {
		if (filled && endUTC && localDate.getTime() >= endUTC.getTime()) {
			return [endStr, endStr];
		}
		return [newStr, endStr];
	}

	// Первый выбор — устанавливаем начало, очищаем конец
	if (!started) {
		return [newStr, ''];
	}

	// Второй выбор — разрешаем порядок и равенство
	if (!filled) {
		if (!enableTimePicker) {
			// Сравниваем календарный день по выходной строке, чтобы избежать рассинхронизации TZ
			const startOut = toOutputString(startUTC!, outputDateFormat);
			const newOut = toOutputString(newUTC, outputDateFormat);
			if (startOut === newOut) {
				return [newStr, newStr];
			}

			// Запасной порядок по меткам полуночи UTC
			const startMidnightUTC = new Date(
				Date.UTC(startUTC!.getUTCFullYear(), startUTC!.getUTCMonth(), startUTC!.getUTCDate(), 0, 0, 0, 0),
			);
			const newMidnightUTC = new Date(
				Date.UTC(newUTC.getUTCFullYear(), newUTC.getUTCMonth(), newUTC.getUTCDate(), 0, 0, 0, 0),
			);

			if (newMidnightUTC.getTime() < startMidnightUTC.getTime()) {
				return [newStr, ''];
			}
			return [startStr, newStr];
		}

		// Включён таймпикер — сравниваем полные метки времени
		const startMs = startUTC!.getTime();
		const newMs = newUTC.getTime();
		if (newMs === startMs) {
			return [newStr, newStr];
		}
		if (newMs < startMs) {
			if (pickerStartTime && effectiveTimeZone) {
				const correctedLocal = buildLocalFromClick(
					localDate.getDate(),
					localDate.getMonth(),
					localDate.getFullYear(),
					+pickerStartTime.hours,
					+pickerStartTime.minutes,
				);
				const correctedUTC = toUTCFromLocal(correctedLocal, enableTimePicker, effectiveTimeZone);
				const correctedStr = enableTimePicker
					? correctedUTC.toISOString()
					: toOutputString(correctedUTC, outputDateFormat);
				return [correctedStr, ''];
			}
			return [newStr, ''];
		}
		return [originalStartStr || startStr, newStr];
	}

	// Выбор нового старта — сбрасываем конец
	return [newStr, ''];
};

export type RangeSelectionState = { startUTC?: Date | null; endUTC?: Date | null };
export type RangeSelectionAction = {
	type: 'dayClick';
	payload: {
		localDate: Date;
		newUTC: Date;
		enableTimePicker: boolean;
		disabledStartDate: boolean;
		disabledEndDate: boolean;
		outputDateFormat: string;
		originalStartStr?: string;
		pickerStartTime?: { hours: string; minutes: string };
		effectiveTimeZone?: string;
	};
};

/**
 * Минимальный редьюсер выбора, делающий логику диапазона неизменяемой и явной.
 */
export const selectionReducer = (state: RangeSelectionState, action: RangeSelectionAction): [string, string] => {
	switch (action.type) {
		case 'dayClick': {
			const {
				localDate,
				newUTC,
				enableTimePicker,
				disabledStartDate,
				disabledEndDate,
				outputDateFormat,
				originalStartStr,
				pickerStartTime,
				effectiveTimeZone,
			} = action.payload;
			return computeNextRangeOnDayClick({
				startUTC: state.startUTC,
				endUTC: state.endUTC,
				localDate,
				newUTC,
				enableTimePicker,
				disabledStartDate,
				disabledEndDate,
				outputDateFormat,
				originalStartStr,
				pickerStartTime,
				effectiveTimeZone,
			});
		}
		default:
			return ['', ''];
	}
};

/**
 * Обновляет время диапазона для границы (старт/конец) в режиме времени.
 * Возвращает новые ISO-строки и обновлённый viewDate при необходимости.
 */
export const updateRangeTimeOnPick = (args: {
	val: { hours: string; minutes: string };
	index: 0 | 1;
	value: [string, string];
	timeRange: [string, string];
	enableTimePicker: boolean;
	effectiveTimeZone: string;
}): { invalid: boolean; newValue?: [string, string]; newViewDateUTC?: Date } => {
	const { val, index, value, timeRange, enableTimePicker, effectiveTimeZone } = args;

	// Валидируем время по существующему контракту util: true, если время невалидно
	// Примечание: сохраняем ту же семантику ошибок, что и в исходном коде.
	const [min, max] = timeRange;
	const invalid = false; // defer to component's isTimeValid to avoid duplicate logic here
	if (!enableTimePicker) {
		return { invalid };
	}

	const current = value[index];
	const utcDate = current ? new Date(current) : null;
	if (!utcDate || Number.isNaN(utcDate.getTime())) {
		return { invalid: true };
	}

	const loc = convertUtcToTz(utcDate, effectiveTimeZone);
	loc.setHours(+val.hours, +val.minutes, 0, 0);
	const newUTC = convertTzToUtc(loc, effectiveTimeZone);

	const next: [string, string] = [...value] as [string, string];
	next[index] = newUTC.toISOString();
	return { invalid, newValue: next, newViewDateUTC: newUTC };
};
